    private static function handle_register() {
        if (!isset($_POST['_wpnonce']) || !wp_verify_nonce($_POST['_wpnonce'], self::NONCE_REGISTER)) {
            self::add_flash('spa_register_error', 'Invalid request.');
            return;
        }

        $username = isset($_POST['spa_username']) ? sanitize_user(wp_unslash($_POST['spa_username'])) : '';
        $email    = isset($_POST['spa_email']) ? sanitize_email(wp_unslash($_POST['spa_email'])) : '';
        $pass1    = isset($_POST['spa_password']) ? (string) wp_unslash($_POST['spa_password']) : '';
        $pass2    = isset($_POST['spa_password2']) ? (string) wp_unslash($_POST['spa_password2']) : '';

        if ($username === '' || $email === '' || $pass1 === '') {
            self::add_flash('spa_register_error', 'Please fill in all required fields.');
            return;
        }
        if (!is_email($email)) {
            self::add_flash('spa_register_error', 'Invalid email address.');
            return;
        }
        if ($pass1 !== $pass2) {
            self::add_flash('spa_register_error', 'Passwords do not match.');
            return;
        }
        if (username_exists($username)) {
            self::add_flash('spa_register_error', 'Username already exists.');
            return;
        }
        if (email_exists($email)) {
            self::add_flash('spa_register_error', 'Email already exists.');
            return;
        }

        $user_id = wp_create_user($username, wp_generate_password(64, true, true), $email);
        if (is_wp_error($user_id)) {
            self::add_flash('spa_register_error', $user_id->get_error_message());
            return;
        }

        $hash = self::hash_password($pass1);
        if (!$hash) {
            wp_delete_user($user_id);
            self::add_flash('spa_register_error', 'Could not create password.');
            return;
        }

        update_user_meta($user_id, self::META_HASH, $hash);

        self::add_flash('spa_register_success', 'Registration successful. You can now log in.');
        $redirect = !empty($_POST['spa_redirect']) ? esc_url_raw(wp_unslash($_POST['spa_redirect'])) : '';
        if ($redirect) {
