    private static function handle_login() {
        if (!isset($_POST['_wpnonce']) || !wp_verify_nonce($_POST['_wpnonce'], self::NONCE_LOGIN)) {
            self::add_flash('spa_login_error', 'Invalid request.');
            return;
        }

        $login    = isset($_POST['spa_login']) ? sanitize_text_field(wp_unslash($_POST['spa_login'])) : '';
        $password = isset($_POST['spa_password']) ? (string) wp_unslash($_POST['spa_password']) : '';
        $remember = !empty($_POST['spa_remember']);

        if ($login === '' || $password === '') {
            self::add_flash('spa_login_error', 'Please enter your login and password.');
            return;
        }

        $creds = [
            'user_login'    => $login,
            'user_password' => $password,
            'remember'      => $remember,
        ];

        $user = wp_signon($creds, is_ssl());
        if (is_wp_error($user)) {
            self::add_flash('spa_login_error', $user->get_error_message());
            return;
        }

        self::add_flash('spa_login_success', 'Login successful.');
        $redirect = !empty($_POST['spa_redirect']) ? esc_url_raw(wp_unslash($_POST['spa_redirect'])) : '';
        if ($redirect) {
            wp_safe_redirect($redirect);
            exit;
        }
