    public static function authenticate($user, $username, $password) {
        if ($user instanceof WP_User) return $user;

        $username = (string) $username;
        $password = (string) $password;

        if ($username === '' || $password === '') return $user;

        $wp_user = get_user_by('login', $username);
        if (!$wp_user && is_email($username)) {
            $wp_user = get_user_by('email', $username);
        }
        if (!$wp_user) return $user;

        $hash = get_user_meta($wp_user->ID, self::META_HASH, true);
        if (!is_string($hash) || $hash === '') return $user;

        if (!self::verify_password($password, $hash)) {
            return new WP_Error('spa_invalid_password', __('Incorrect password.', 'spa'));
        }

        self::maybe_rehash($password, $hash, $wp_user->ID);

        return $wp_user;
    }

    public static function on_user_register($user_id) {
        $hash = get_user_meta($user_id, self::META_HASH, true);
        if (is_string($hash) && $hash !== '') return;

        $random = wp_generate_password(64, true, true);
        update_user_meta($user_id, self::META_HASH, self::hash_password($random));
    }

