    private static function add_flash($key, $message) {
        if (!session_id()) {
            if (!headers_sent()) {
                @session_start();
            }
        }
        if (session_id()) {
            $_SESSION[$key] = (string) $message;
        } else {
            set_transient($key . '_' . md5(self::client_key()), (string) $message, 60);
        }
    }

    private static function get_flash($key) {
        $val = null;

        if (!session_id()) {
            if (!headers_sent()) {
                @session_start();
            }
        }

        if (session_id() && isset($_SESSION[$key])) {
            $val = (string) $_SESSION[$key];
            unset($_SESSION[$key]);
            return $val;
        }

        $tkey = $key . '_' . md5(self::client_key());
        $val = get_transient($tkey);
        if ($val !== false) {
            delete_transient($tkey);
            return (string) $val;
        }

        return null;
    }

    private static function client_key() {
        $ip = isset($_SERVER['REMOTE_ADDR']) ? (string) $_SERVER['REMOTE_ADDR'] : '';
        $ua = isset($_SERVER['HTTP_USER_AGENT']) ? (string) $_SERVER['HTTP_USER_AGENT'] : '';
        return $ip . '|' . $ua;
    }
